 }

 bool VPInstruction::doesGeneratePerAllLanes() const {
-  return Opcode == VPInstruction::PtrAdd && !vputils::onlyFirstLaneUsed(this);
+  // PtrAdd instructions should always generate per all lanes when vectorizing,
+  // because pointer arithmetic depends on the lane-specific values of their operands.
+  if (Opcode == VPInstruction::PtrAdd) {
+    // Check if any operand requires per-lane access (is not uniform).
+    for (VPValue *Op : operands()) {
+      if (!vputils::isUniformAfterVectorization(Op))
+        return true;
+    }
+    // If all operands are uniform, we only need to generate for the first lane
+    // if the result is only used in the first lane.
+    return !vputils::onlyFirstLaneUsed(this);
+  }
+  return false;
 }

